ue.push([i, j, 0]); // [row, col, distance]\n    }\n  }\n}\n\n// Step 2: Multi-source BFS from all rabbit holes\nwhile (queue.length > 0) {\n  const [row, col, distance] = queue.shift();\n  \n  // Explore 4 directions\n  for (const [dr, dc] of directions) {\n    const newRow = row + dr;\n    const newCol = col + dc;\n    \n    // Check bounds and if cell is a rabbit (value 1)\n    if (\n      newRow >= 0 && newRow < rows &&\n      newCol >= 0 && newCol < cols &&\n      grid[newRow][newCol] === 1\n    ) {\n      // Update rabbit cell with distance + 1\n      grid[newRow][newCol] = distance + 1;\n      queue.push([newRow, newCol, distance + 1]);\n    }\n  }\n}\n}\n\n// Test cases\nconst grid1 = [\n[-1, 0, 1],\n[1, 1, -1],\n[1, 1, 0]\n];\nupdateRabbitDistances(grid1);\nconsole.log('Example 1:', grid1);\n// [[-1, 0, 1], [2, 1, -1], [2, 1, 0]]\n\nconst grid2 = [\n[1, 1, 1],\n[1, -1, -1],\n[1, 1, 0]\n];\nupdateRabbitDistances(grid2);\nconsole.log('Example 2:', grid2);\n// [[4, 5, 6], [3, -1, -1], [2, 1, 0]]",testCases:[{input:"(grid => { updateRabbitDistances(grid); return JSON.stringify(grid); })([[-1,0,1],[1,1,-1],[1,1,0]])",expected:"[[-1,0,1],[2,2,-1],[2,2,0]]"},{input:"(grid => { updateRabbitDistances(grid); return JSON.stringify(grid); })([[1,1,1],[1,-1,-1],[1,1,0]])",expected:"[[4,5,6],[3,-1,-1],[2,3,0]]"}]})}),(0,r.jsx)(l.A,{value:"python",label:"Python Solution",children:(0,r.jsx)(o.A,{language:"python",title:"Python Solution - Multi-source BFS",code:'from typing import List\nfrom collections import deque\n\ndef update_rabbit_distances(grid: List[List[int]]) -> None:\n  """\n  Update rabbit cells with distance to nearest rabbit hole\n  \n  Args:\n      grid: 2D array (-1=obstacle, 0=hole, 1=rabbit), modified in-place\n  """\n  if not grid or not grid[0]:\n      return\n  \n  rows = len(grid)\n  cols = len(grid[0])\n  queue = deque()\n  directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]\n  \n  # Step 1: Find all rabbit holes (value 0) and add to queue\n  for i in range(rows):\n      for j in range(cols):\n          if grid[i][j] == 0:\n              queue.append((i, j, 0))  # (row, col, distance)\n  \n  # Step 2: Multi-source BFS from all rabbit holes\n  while queue:\n      row, col, distance = queue.popleft()\n      \n      # Explore 4 directions\n      for dr, dc in directions:\n          new_row = row + dr\n          new_col = col + dc\n          \n          # Check bounds and if cell is a rabbit (value 1)\n          if (\n              0 <= new_row < rows and\n              0 <= new_col < cols and\n              grid[new_row][new_col] == 1\n          ):\n              # Update rabbit cell with distance + 1\n              grid[new_row][new_col] = distance + 1\n              queue.append((new_row, new_col, distance + 1))\n\n# Test cases\ngrid1 = [\n  [-1, 0, 1],\n  [1, 1, -1],\n  [1, 1, 0]\n]\nupdate_rabbit_distances(grid1)\nprint(\'Example 1:\', grid1)\n# [[-1, 0, 1], [2, 1, -1], [2, 1, 0]]\n\ngrid2 = [\n  [1, 1, 1],\n  [1, -1, -1],\n  [1, 1, 0]\n]\nupdate_rabbit_distances(grid2)\nprint(\'Example 2:\', grid2)\n# [[4, 5, 6], [3, -1, -1], [2, 1, 0]]',testCases:[{input:"(lambda grid: (update_rabbit_distances(grid), grid)[1])([[-1,0,1],[1,1,-1],[1,1,0]])",expected:"[[-1, 0, 1], [2, 2, -1], [2, 2, 0]]"},{input:"(lambda grid: (update_rabbit_distances(grid), grid)[1])([[1,1,1],[1,-1,-1],[1,1,0]])",expected:"[[4, 5, 6], [3, -1, -1], [2, 3, 0]]"}]})})]}),"\n",(0,r.jsx)(n.h2,{id:"complexity",children:"Complexity"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Time Complexity:"})," O(m \xd7 n) - Where m and n are the dimensions of the grid. We visit each cell at most once."]}),"\n",(0,r.jsxs)(n.li,{children:[(0,r.jsx)(n.strong,{children:"Space Complexity:"})," O(m \xd7 n) - For the BFS queue in the worst case."]}),"\n"]}),"\n",(0,r.jsx)(n.h2,{id:"approach",children:"Approach"}),"\n",(0,r.jsxs)(n.p,{children:["The solution uses ",(0,r.jsx)(n.strong,{children:"Multi-source BFS"}),":"]}),"\